  3 | import { useState } from "react";
  4 | import { useRouter } from "next/navigation";
  5 | import { useAuth } from "@/lib/auth";
  6 | import { users, updateUser, getUserById, type User } from "@/data/users";
  7 | import type { UserRole } from "@/data/users";
  8 | import Link from "next/link";
  9 | 
 10 | import {
 11 |   Breadcrumb,
 12 |   BreadcrumbList,
 13 |   BreadcrumbItem,
 14 |   BreadcrumbLink,
 15 |   BreadcrumbSeparator,
 16 |   BreadcrumbPage,
 17 | } from "@/components/ui/breadcrumb";
 18 | import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
 19 | import { Field, FieldGroup, FieldSet, FieldLabel, FieldError } from "@/components/ui/field";
 20 | import { Input } from "@/components/ui/input";
 21 | import { Button } from "@/components/ui/button";
 22 | import { Separator } from "@/components/ui/separator";
 23 | import { Badge } from "@/components/ui/badge";
 24 | import { Alert, AlertTitle, AlertDescription } from "@/components/ui/alert";
 25 | 
 26 | function formatRole(role: UserRole): string {
 27 |   return role
 28 |     .split("_")
 29 |     .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
 30 |     .join(" ");
 31 | }
 32 | 
 33 | export default function SettingsPage() {
 34 |   const { user, logout, updatePassword } = useAuth();
 35 |   const router = useRouter();
 36 | 
 37 |   const currentUser = user ? getUserById(user.id) : null;
 38 | 
 39 |   // Profile form state
 40 |   const [name, setName] = useState(currentUser?.name ?? "");
 41 |   const [jobTitle, setJobTitle] = useState(currentUser?.jobTitle ?? "");
 42 |   const [weeklyCapacity, setWeeklyCapacity] = useState(String(currentUser?.weeklyCapacity ?? 48));
 43 |   const [profileSaved, setProfileSaved] = useState(false);
 44 |   const [profileError, setProfileError] = useState("");
 45 | 
 46 |   // Password form state
 47 |   const [currentPassword, setCurrentPassword] = useState("");
 48 |   const [newPassword, setNewPassword] = useState("");
 49 |   const [confirmPassword, setConfirmPassword] = useState("");
 50 |   const [passwordMessage, setPasswordMessage] = useState("");
 51 |   const [passwordError, setPasswordError] = useState("");
 52 | 
 53 |   if (!user || !currentUser) {
 54 |     router.push("/auth/signin");
 55 |     return null;
 56 |   }
 57 | 
 58 |   const userId = user.id;
 59 |   const isAdmin = user.role === "ops_admin" || user.role === "agency_owner";
 60 |   const isClient = user.role === "client";
 61 | 
 62 |   function handleSaveProfile(e: React.FormEvent) {
 63 |     e.preventDefault();
 64 |     setProfileSaved(false);
 65 |     setProfileError("");
 66 | 
 67 |     if (!isAdmin) {
 68 |       setProfileError("Only administrators can edit profile information.");
 69 |       return;
 70 |     }
 71 | 
 72 |     if (!name.trim()) {
 73 |       setProfileError("Name is required.");
 74 |       return;
 75 |     }
 76 | 
 77 |     const updateData: Partial<Omit<User, "id">> = {
 78 |       name: name.trim(),
 79 |     };
 80 | 
 81 |     if (!isClient) {
 82 |       updateData.jobTitle = jobTitle.trim() || undefined;
 83 |       updateData.weeklyCapacity = Number(weeklyCapacity) || 48;
 84 |     }
 85 | 
 86 |     const updated = updateUser(userId, updateData);
 87 |     if (updated) {
 88 |       setProfileSaved(true);
 89 |       setTimeout(() => setProfileSaved(false), 3000);
 90 |     } else {
 91 |       setProfileError("Failed to update profile.");
 92 |     }
 93 |   }
 94 | 
 95 |   function handleChangePassword(e: React.FormEvent) {
 96 |     e.preventDefault();
 97 |     setPasswordMessage("");
 98 |     setPasswordError("");
 99 | 
100 |     if (!currentPassword || !newPassword || !confirmPassword) {
101 |       setPasswordError("All password fields are required.");
102 |       return;
103 |     }
104 | 
105 |     if (newPassword.length < 6) {
106 |       setPasswordError("New password must be at least 6 characters.");
107 |       return;
108 |     }
109 | 
110 |     if (newPassword !== confirmPassword) {
111 |       setPasswordError("New passwords do not match.");
112 |       return;
113 |     }
114 | 
115 |     const success = updatePassword(userId, currentPassword, newPassword);
116 |     if (success) {
117 |       setPasswordMessage("Password updated successfully.");
118 |       setCurrentPassword("");
119 |       setNewPassword("");
120 |       setConfirmPassword("");
121 |     } else {
122 |       setPasswordError("Current password is incorrect.");
123 |     }
124 |   }
125 | 
126 |   return (
127 |     <div className="flex flex-col gap-6 p-6">
128 |       <Breadcrumb>
129 |         <BreadcrumbList>
130 |           <BreadcrumbItem>
131 |             <BreadcrumbPage>Settings</BreadcrumbPage>
132 |           </BreadcrumbItem>
133 |         </BreadcrumbList>
134 |       </Breadcrumb>
135 | 
136 |       <div className="max-w-2xl space-y-6">
137 |         {/* Section 1: Profile */}
138 |         <Card>
139 |           <CardHeader>
140 |             <CardTitle className="text-xl">Profile</CardTitle>
141 |             <CardDescription>
142 |               {isAdmin ? "Update your personal information." : "View your profile information. Contact an administrator to make changes."}
143 |             </CardDescription>
144 |           </CardHeader>
145 |           <CardContent>
146 |             <form onSubmit={handleSaveProfile}>
147 |               <FieldSet>
148 |                 <FieldGroup>
149 |                   <Field>
150 |                     <FieldLabel htmlFor="name">Name</FieldLabel>
151 |                     <Input
152 |                       id="name"
153 |                       value={name}
154 |                       onChange={(e) => setName(e.target.value)}
155 |                       disabled={!isAdmin}
156 |                     />
157 |                     <FieldError
158 |                       errors={
159 |                         profileError && !name.trim()
160 |                           ? [{ message: profileError }]
161 |                           : undefined
162 |                       }
163 |                     />
164 |                   </Field>
165 | 
166 |                   <Field>
167 |                     <FieldLabel htmlFor="email">Email</FieldLabel>
168 |                     <Input
169 |                       id="email"
170 |                       value={currentUser.email}
171 |                       disabled
172 |                     />
173 |                   </Field>
174 | 
175 |                   {!isClient && (
176 |                     <Field>
177 |                       <FieldLabel htmlFor="jobTitle">Job Title</FieldLabel>
178 |                       <Input
179 |                         id="jobTitle"
180 |                         value={jobTitle}
181 |                         onChange={(e) => setJobTitle(e.target.value)}
182 |                         placeholder="e.g. Designer, Developer"
183 |                         disabled={!isAdmin}
184 |                       />
185 |                     </Field>
186 |                   )}
187 | 
188 |                   {!isClient && (
189 |                     <Field>
190 |                       <FieldLabel htmlFor="capacity">Weekly Capacity (hours)</FieldLabel>
191 |                       <Input
192 |                         id="capacity"
193 |                         type="number"
194 |                         min="0"
195 |                         value={weeklyCapacity}
196 |                         onChange={(e) => setWeeklyCapacity(e.target.value)}
197 |                         disabled={!isAdmin}
198 |                       />
199 |                     </Field>
200 |                   )}
201 | 
202 |                   {profileError && (
203 |                     <Alert variant="destructive">
204 |                       <AlertDescription>{profileError}</AlertDescription>
205 |                     </Alert>
206 |                   )}
207 | 
208 |                   {profileSaved && (
209 |                     <Alert>
210 |                       <AlertTitle>Profile Updated</AlertTitle>
211 |                       <AlertDescription>Your changes have been saved.</AlertDescription>
212 |                     </Alert>
213 |                   )}
214 |                 </FieldGroup>
215 |               </FieldSet>
216 |               {isAdmin && (
217 |                 <div className="mt-4 flex justify-end">
218 |                   <Button type="submit">Save Changes</Button>
219 |                 </div>
220 |               )}
221 |             </form>
222 |           </CardContent>
223 |         </Card>
224 | 
225 |         {/* Section 2: Change Password */}
226 |         <Card>
227 |           <CardHeader>
228 |             <CardTitle className="text-xl">Change Password</CardTitle>
229 |             <CardDescription>Update your account password.</CardDescription>
230 |           </CardHeader>
231 |           <CardContent>
232 |             <form onSubmit={handleChangePassword}>
233 |               <FieldSet>
234 |                 <FieldGroup>
235 |                   <Field>
236 |                     <FieldLabel htmlFor="currentPassword">Current Password</FieldLabel>
237 |                     <Input
238 |                       id="currentPassword"
239 |                       type="password"
240 |                       value={currentPassword}
241 |                       onChange={(e) => setCurrentPassword(e.target.value)}
242 |                     />
243 |                   </Field>
244 | 
245 |                   <Field>
246 |                     <FieldLabel htmlFor="newPassword">New Password</FieldLabel>
247 |                     <Input
248 |                       id="newPassword"
249 |                       type="password"
250 |                       value={newPassword}
251 |                       onChange={(e) => setNewPassword(e.target.value)}
252 |                     />
253 |                   </Field>
254 | 
255 |                   <Field>
256 |                     <FieldLabel htmlFor="confirmPassword">Confirm New Password</FieldLabel>
257 |                     <Input
258 |                       id="confirmPassword"
259 |                       type="password"
260 |                       value={confirmPassword}
261 |                       onChange={(e) => setConfirmPassword(e.target.value)}
262 |                     />
263 |                   </Field>
264 | 
265 |                   {passwordError && (
266 |                     <Alert variant="destructive">
267 |                       <AlertDescription>{passwordError}</AlertDescription>
268 |                     </Alert>
269 |                   )}
270 | 
271 |                   {passwordMessage && (
272 |                     <Alert>
273 |                       <AlertTitle>Success</AlertTitle>
274 |                       <AlertDescription>{passwordMessage}</AlertDescription>
275 |                     </Alert>
276 |                   )}
277 |                 </FieldGroup>
278 |               </FieldSet>
279 |               <div className="mt-4 flex justify-end">
280 |                 <Button type="submit">Update Password</Button>
281 |               </div>
282 |             </form>
283 |           </CardContent>
284 |         </Card>
285 | 
286 |         {/* Section 3: Admin - Manage Users */}
287 |         {isAdmin && (
288 |           <Card>
289 |             <CardHeader>
290 |               <CardTitle className="text-xl">Manage Users</CardTitle>
291 |               <CardDescription>View and manage all agency users.</CardDescription>
292 |             </CardHeader>
293 |             <CardContent>
294 |               <div className="space-y-3">
295 |                 {users.map((u) => (
296 |                   <div key={u.id} className="flex items-center justify-between rounded-lg border p-3">
297 |                     <div className="flex flex-col">
298 |                       <span className="font-medium">{u.name}</span>
299 |                       <span className="text-sm text-muted-foreground">{u.email}</span>
300 |                     </div>
301 |                     <div className="flex items-center gap-2">
302 |                       <Badge variant="secondary">{formatRole(u.role)}</Badge>
303 |                       <Button asChild variant="outline" size="sm">
304 |                         <Link href={`/team/member/${u.id}/edit`}>Edit</Link>
305 |                       </Button>
306 |                     </div>
307 |                   </div>
308 |                 ))}
309 |               </div>
310 |             </CardContent>
311 |           </Card>
312 |         )}
313 |       </div>
314 |     </div>
315 |   );
316 | }
